using TranSmart.Core.Result;
using TranSmart.Data;
using TranSmart.Data.Paging;
using TranSmart.Domain.Entities.Payroll;
using TranSmart.Domain.Models;
using Microsoft.EntityFrameworkCore;
using System.Collections.Generic;
using System;
using System.Linq;
using System.Threading.Tasks;

namespace TranSmart.Service.Payroll
{
    public partial interface IBankService : IBaseService<Bank>
    {

    }

    public partial class BankService : BaseService<Bank>, IBankService
    {
        public BankService(IUnitOfWork uow) : base(uow)
        {

        }

        public override async Task Validation(Bank item, Result<Bank> executionResult)
        {
            if (await UOW.GetRepositoryAsync<Bank>().HasRecordsAsync(x => x.Name == item.Name && x.Status == true && x.ID != item.ID))
            {
                executionResult.AddMessageItem(new MessageItem(nameof(Bank.Name), "Name already exists"));
            }
        }
        public override async Task<Bank> GetById(Guid id)
        {
            return await UOW.GetRepositoryAsync<Bank>().SingleAsync(
                predicate: x => x.ID == id,
                orderBy: o => o.OrderByDescending(x => x.AddedAt));
        }

        public override async Task<IEnumerable<Bank>> GetList(string orderBy)
        {
            return await UOW.GetRepositoryAsync<Bank>().GetListAsync(orderBy, x => x.Status == true);
        }

        public override async Task<IPaginate<Bank>> GetPaginate(BaseSearch search)
        {
            return await UOW.GetRepositoryAsync<Bank>().GetPageListAsync(
                predicate: x => (string.IsNullOrEmpty(search.Name)
                     || x.Name.Contains(search.Name)
                     || x.IFSCCode.Contains(search.Name)
                     || x.DisplayName.Contains(search.Name)),
                index: search.Page, size: search.Size, sortBy: search.SortBy ?? "Name", ascending: !search.IsDescend);
        }
    }
}
